S */; INSERT INTO `blog_comments` VALUES (1,1,'John Doe','john@example.com','This is a fantastic and very detailed article! I followed your tips on visiting Borobudur at sunrise and it was absolutely magical. Thank you for the guide.','approved','192.168.1.1','2026-07-06 08:26:12','2026-07-09 08:26:12'),(2,2,'Siti Aminah','siti.aminah@gmail.com','Gudeg Yu Djum memang paling legendaris! Saya selalu mampir ke sana setiap kali liburan ke Jogja. Terima kasih rekomendasinya.','approved','192.168.1.2','2026-07-07 08:26:12','2026-07-09 08:26:12'),(3,3,'Budi Santoso','budi.santoso@yahoo.com','Apakah di candi Borobudur sekarang boleh naik ke atas stupa utamanya? Mohon infonya dong.','pending','192.168.1.3','2026-07-09 03:26:12','2026-07-09 08:26:12'),(4,4,'Michael Smith','mikesmith@example.com','Hi, is it possible to hire a private driver directly from this site for the Borobudur and Prambanan tour? How much would it be for 3 days?','pending','192.168.1.4','2026-07-09 06:26:12','2026-07-09 08:26:12'),(5,1,'Spam Bot','spambot@casino.com','Play free online poker and win real money now at http://cheatcasinosite.com! Best rates ever.','rejected','203.0.113.50','2026-07-08 08:26:12','2026-07-09 08:26:12'); /*!40000 ALTER TABLE `blog_comments` ENABLE KEYS */; UNLOCK TABLES;  -- -- Table structure for table `blogs` --  DROP TABLE IF EXISTS `blogs`; /*!40101 SET @saved_cs_client     = @@character_set_client */; /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `blogs` (   `id` bigint unsigned NOT NULL AUTO_INCREMENT,   `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `content` text COLLATE utf8mb4_unicode_ci NOT NULL,   `excerpt` text COLLATE utf8mb4_unicode_ci,   `image` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `author_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Admin',   `author_avatar` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,   `category` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Travel',   `view_count` int NOT NULL DEFAULT '0',   `is_active` tinyint(1) NOT NULL DEFAULT '1',   `created_at` timestamp NULL DEFAULT NULL,   `updated_at` timestamp NULL DEFAULT NULL,   PRIMARY KEY (`id`),   UNIQUE KEY `blogs_slug_unique` (`slug`) ) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; /*!40101 SET character_set_client = @saved_cs_client */;  -- -- Dumping data for table `blogs` --  LOCK TABLES `blogs` WRITE; /*!40000 ALTER TABLE `blogs` DISABLE KEYS */; INSERT INTO `blogs` VALUES (1,'10 Best Places to Visit in Yogyakarta','10-best-places-to-visit-in-yogyakarta','<p>Yogyakarta is one of the most popular travel destinations in Indonesia. From historic temples to beautiful beaches, here are the top 10 places you must visit when traveling to Yogyakarta.</p>\n<h4>1. Borobudur Temple</h4>\n<p>The world\'s largest Buddhist temple and a UNESCO World Heritage Site, famous for its stunning sunrise views.</p>\n<h4>2. Prambanan Temple</h4>\n<p>The largest Hindu temple complex in Indonesia, featuring the towering Trimurti temples.</p>\n<h4>3. Malioboro Street</h4>\n<p>The iconic heart of the city, perfect for shopping, street food, and local culture.</p>\n<h4>4. Parangtritis Beach</h4>\n<p>A legendary black-sand beach with dramatic waves and rich Javanese folklore.</p>\n<h4>5. Taman Sari Water Castle</h4>\n<p>The former royal garden of the Yogyakarta Sultanate with unique architecture.</p>\n<h4>6. Mount Merapi</h4>\n<p>An active volcano offering thrilling jeep lava tours and breathtaking landscapes.</p>\n<h4>7. Jomblang Cave</h4>\n<p>A natural wonder where sunlight streams into a vertical cave for a magical experience.</p>\n<h4>8. Kotagede</h4>\n<p>A historic silver-crafting district with charming old architecture.</p>\n<h4>9. Kaliurang</h4>\n<p>A cool highland retreat on the slopes of Mount Merapi.</p>\n<h4>10. Pinus Pengger</h4>\n<p>A pine forest with panoramic viewpoints and unique photo spots.</p>','Yogyakarta is one of the most popular travel destinations in Indonesia, offering a perfect blend of culture, history, and natural beauty.','template/assets/images/blog/bl1.jpg','Admin','template/assets/images/avata/1.jpg','Travel',1250,1,'2026-07-09 00:15:27','2026-07-09 09:15:32'),(2,'Budget Travel Tips for Yogyakarta','budget-travel-tips-for-yogyakarta','<p>Traveling to Yogyakarta doesn\'t have to break the bank. With the right planning and guide, you can enjoy this beautiful city within a highly affordable budget.</p>\n<h4>Use Public Transport</h4>\n<p>Trans Jogja buses and local becak offer cheap ways to get around the city.</p>\n<h4>Eat Like a Local</h4>\n<p>Warungs and street food stalls serve delicious meals at a fraction of restaurant prices.</p>\n<h4>Visit Free Attractions</h4>\n<p>Many temples and natural spots have low or no entrance fees, especially early in the day.</p>\n<h4>Book Packages in Advance</h4>\n<p>Bundling tours often saves more than booking each activity separately.</p>','Traveling to Yogyakarta doesn\'t have to break the bank. With the right planning, you can enjoy the city on an affordable budget.','template/assets/images/blog/bl2.jpg','Admin','template/assets/images/avata/2.jpg','Tips',890,1,'2026-07-09 00:15:27','2026-07-09 09:15:32'),(3,'Must-Try Traditional Culinary in Yogyakarta','must-try-traditional-culinary-in-yogyakarta','<p>Yogyakarta is well-known for its delicious and unique culinary heritage. From Gudeg to Bakpia, here are the top traditional dishes you must try during your visit.</p>\n<h4>Gudeg</h4>\n<p>The city\'s signature dish made from young jackfruit, coconut milk, and palm sugar, slow-cooked for hours.</p>\n<h4>Bakpia Pathok</h4>\n<p>Sweet mung-bean pastries that make perfect souvenirs.</p>\n<h4>Sate Klathak</h4>\n<p>Grilled mutton satay with a distinctive savory flavor, served with soy sauce.</p>\n<h4>Oseng Mercon</h4>\n<p>A spicy stir-fried beef tendon dish for those who love heat.</p>','Yogyakarta is well-known for its delicious and unique culinary heritage that you shouldn\'t miss.','template/assets/images/blog/bl3.jpg','Admin','template/assets/images/avata/3.jpg','Food',756,1,'2026-07-09 00:15:27','2026-07-09 09:15:32'),(4,'Ultimate Guide to Visiting Borobudur Temple','ultimate-guide-to-visiting-borobudur-temple','<p>Borobudur Temple is a magnificent UNESCO World Heritage Site that you must visit. Here is the ultimate guide to make the most of your visit to the world\'s largest Buddhist monument.</p>\n<h4>Best Time to Go</h4>\n<p>Arrive at sunrise (around 4:30 AM) for cooler weather and the most spectacular views.</p>\n<h4>What to Wear</h4>\n<p>A sarong is required inside the temple complex. Wear comfortable shoes for climbing the stairs.</p>\n<h4>Getting There</h4>\n<p>Borobudur is about 1.5 hours from Yogyakarta city center. Guided tours with hotel pickup are the easiest option.</p>\n<h4>Nearby Attractions</h4>\n<p>Combine your visit with Mendut and Pawon temples for a complete experience.</p>','The ultimate guide to making the most of your visit to the magnificent Borobudur Temple.','template/assets/images/blog/bl4.jpg','Admin','template/assets/images/avata/4.jpg','Travel',654,1,'2026-07-09 00:15:27','2026-07-09 09:15:32'); /*!40000 ALTER TABLE `blogs` ENABLE KEYS */; UNLOCK TABLES;  -- -- Table structure for table `cache` --  DROP TABLE IF EXISTS `cache`; /*!40101 SET @saved_cs_client     = @@character_set_client */; /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `cache` (   `key` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `value` mediumtext COLLATE utf8mb4_unicode_ci NOT NULL,   `expiration` bigint NOT NULL,   PRIMARY KEY (`key`),   KEY `cache_expiration_index` (`expiration`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; /*!40101 SET character_set_client = @saved_cs_client */;  -- -- Dumping data for table `cache` --  LOCK TABLES `cache` WRITE; /*!40000 ALTER TABLE `cache` DISABLE KEYS */; INSERT INTO `cache` VALUE