 /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `destination_galleries` (   `id` bigint unsigned NOT NULL AUTO_INCREMENT,   `destination_id` bigint unsigned NOT NULL,   `image` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `sort_order` int NOT NULL DEFAULT '0',   `created_at` timestamp NULL DEFAULT NULL,   `updated_at` timestamp NULL DEFAULT NULL,   PRIMARY KEY (`id`),   KEY `destination_galleries_destination_id_foreign` (`destination_id`),   CONSTRAINT `destination_galleries_destination_id_foreign` FOREIGN KEY (`destination_id`) REFERENCES `destinations` (`id`) ON DELETE CASCADE ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; /*!40101 SET character_set_client = @saved_cs_client */;  -- -- Dumping data for table `destination_galleries` --  LOCK TABLES `destination_galleries` WRITE; /*!40000 ALTER TABLE `destination_galleries` DISABLE KEYS */; /*!40000 ALTER TABLE `destination_galleries` ENABLE KEYS */; UNLOCK TABLES;  -- -- Table structure for table `destinations` --  DROP TABLE IF EXISTS `destinations`; /*!40101 SET @saved_cs_client     = @@character_set_client */; /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `destinations` (   `id` bigint unsigned NOT NULL AUTO_INCREMENT,   `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `description` text COLLATE utf8mb4_unicode_ci NOT NULL,   `short_description` text COLLATE utf8mb4_unicode_ci,   `image` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `location` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `city` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Yogyakarta',   `rating` decimal(3,2) NOT NULL DEFAULT '5.00',   `tour_count` int NOT NULL DEFAULT '0',   `maps_embed` text COLLATE utf8mb4_unicode_ci,   `maps_link` text COLLATE utf8mb4_unicode_ci,   `gallery_images` json DEFAULT NULL,   `is_featured` tinyint(1) NOT NULL DEFAULT '0',   `is_active` tinyint(1) NOT NULL DEFAULT '1',   `created_at` timestamp NULL DEFAULT NULL,   `updated_at` timestamp NULL DEFAULT NULL,   PRIMARY KEY (`id`),   UNIQUE KEY `destinations_slug_unique` (`slug`) ) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; /*!40101 SET character_set_client = @saved_cs_client */;  -- -- Dumping data for table `destinations` --  LOCK TABLES `destinations` WRITE; /*!40000 ALTER TABLE `destinations` DISABLE KEYS */; INSERT INTO `destinations` VALUES (1,'Borobudur Temple','borobudur-temple','<p><strong>Borobudur Temple</strong> is the world\'s largest Buddhist temple and a UNESCO World Heritage Site, located in Magelang, Central Java, Indonesia. Built between the 8th and 9th centuries CE during the reign of the Sailendra Dynasty, Borobudur stands as one of the greatest archaeological marvels in the world and Indonesia\'s most visited tourist attraction.</p><h4>History</h4><p>Borobudur was constructed around 750ΓÇô850 CE during the Sailendra Dynasty\'s rule over the Medang Kingdom. After the center of power shifted to East Java in the 14th century and with the gradual conversion to Islam, the temple was abandoned and eventually buried under volcanic ash and jungle growth. In 1814, Sir Thomas Stamford Raffles, the then British Governor-General of Java, rediscovered the monument. A major international restoration project was carried out between 1975 and 1982 by the Indonesian Government in collaboration with UNESCO, successfully restoring the temple to its former glory.</p><h4>Architecture &amp; Philosophy</h4><p>Borobudur is designed as a giant stepped pyramid representing a sacred mandala, symbolizing the Buddhist cosmological universe. The structure consists of nine stacked platforms ΓÇö six square terraces and three circular ones ΓÇö topped by a central dome stupa. The monument features 2,672 decorative relief panels and 504 Buddha statues. Architecturally, it embodies three realms of Buddhist cosmology: <em>Kamadhatu</em> (the world of desire), <em>Rupadhatu</em> (the world of forms), and <em>Arupadhatu</em> (the formless world).</p><h4>Reliefs &amp; Statues</h4><p>The temple\'s narrative reliefs depict the life of the Buddha (Lalitavistara), the Jataka tales (stories of Buddha\'s previous incarnations), and the Gandavyuha (the spiritual journey of the young pilgrim Sudhana). The 72 perforated stupas on the upper circular terraces each contain a Buddha statue in the Dharmachakra mudra (the gesture of turning the Wheel of Dharma), many of which can be touched by visitors for good luck.</p><h4>Best Time to Visit</h4><p>The most spectacular time to visit Borobudur is at <strong>sunrise</strong>, around 5:30ΓÇô6:00 AM, when the morning mist rolls in from the surrounding valleys and mountains, creating a mystical atmosphere. Early morning visits also allow you to enjoy the temple before the heat of the day and the crowds. Sunset views from the temple grounds are equally breathtaking. Avoid midday visits due to intense heat and large crowds.</p><h4>Visitor Information</h4><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Location:</strong> Jl. Badrawati, Borobudur, Magelang, Central Java 56553</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Opening Hours:</strong> Daily 06:00 AM ΓÇô 05:00 PM (Special sunrise ticket from 04:30 AM)</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Entrance Fee:</strong> Foreign tourists USD 25 | Domestic tourists IDR 50,000</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span><strong>Distance from Yogyakarta:</strong> Approximately 40 km (about 1ΓÇô1.5 hours by car)</li></ol><h4>Facilities</h4><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Spacious parking area, clean restrooms, and prayer rooms (musalla)</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Karmawibhangga Museum &amp; Samudraraksa Museum (ship museum) on-site</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Licensed tour guides available (highly recommended for deeper insight)</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Canteen, souvenir shops, and rest areas</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Wheelchair-accessible paths in certain zones</li></ol>','<p>The world\'s largest Buddhist temple and a UNESCO World Heritage Site, built by the Sailendra Dynasty in the 8thΓÇô9th century CE in Magelang, Central Java. A timeless masterpiece of ancient architecture and spiritual heritage.</p>','destinations/gallery/borobudur_1783691034.webp','Magelang, Central Java','Yogyakarta',4.90,25,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3954.6973689465976!2d110.2037513!3d-7.6078738!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a8cf009a7d697%3A0xdd34334744dc3cb!2sCandi%20Borobudur!5e0!3m2!1sid!2sid!4v1783588126515!5m2!1sid!2sid\" width=\"100%\" height=\"100%\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"strict-origin-when-cross-origin\"></iframe>','https://maps.app.goo.gl/6vpsNxVWfGvy4QhQ9','[\"template/assets/images/destination/des1.jpg\", \"template/assets/images/destination/des2.jpg\", \"template/assets/images/destination/des3.jpg\", \"template/assets/images/destination/des4.jpg\", \"template/assets/images/destination/des5.jpg\", \"template/assets/images/destination/1.jpg\"]',1,1,'2026-07-09 00:15:27','2026-07-10 06:43:54'),(2,'Prambanan Temple','prambanan-temple','<p><strong>Prambanan Temple</strong> (Candi Prambanan) is the largest Hindu temple compound in Indonesia and one of the most magnificent temple complexes in Southeast Asia. Located about 17 km northeast of Yogyakarta city center in Sleman Regency, this UNESCO World Heritage Site was built in the 9th century during the Mataram Kingdom era.</p>\n<h4>Architecture</h4>\n<p>The main complex features three towering central temples dedicated to the Trimurti ΓÇö Brahma (the Creator), Vishnu (the Preserver), and Shiva (the Destroyer) ΓÇö with the Shiva temple rising to an impressive 47 meters. The temple walls are adorned with intricate bas-relief carvings depicting the Hindu epic <em>Ramayana</em>, among the finest examples of classical Javanese art.</p>\n<h4>The Ramayana Ballet</h4>\n<p>One of Prambanan\'s most iconic experiences is the open-air <strong>Ramayana Ballet</strong>, performed on a stage with the illuminated temple as a backdrop. Held on full moon evenings from May to October, this spectacular dance-drama brings the Ramayana epic to life with hundreds of dancers and musicians. Tickets should be booked well in advance.</p>\n<h4>What to See</h4>\n<ul>\n<li><strong>Shiva Temple</strong> ΓÇö the tallest at 47m, housing a statue of Shiva Mahadeva</li>\n<li><strong>Brahma Temple</strong> ΓÇö features reliefs telling the story of the Ramayana</li>\n<li><strong>Vishnu Temple</strong> ΓÇö contains well-preserved reliefs of the Krishna narrative</li>\n<li><strong>Sewu Temple</strong> ΓÇö a nearby Buddhist temple complex worth visiting</li>\n<li><strong>Candi Plaosan</strong> ΓÇö twin temples just south of the complex</li>\n</ul>\n<h4>Visitor Tips</h4>\n<ul>\n<li>Arrive early morning (opens 6:00 AM) to avoid crowds and heat</li>\n<li>Wear comfortable shoes ΓÇö the complex is large with uneven stone paths</li>\n<li>Bring sunscreen and water; shade is limited</li>\n<li>The sunset view from the temple grounds is stunning</li>\n<li>A joint ticket with Ratu Boko Temple is available</li>\n</ul>\n<p>Prambanan is a must-visit for anyone interested in ancient architecture, Hindu mythology, or simply witnessing one of humanity\'s greatest religious monuments.</p>','A magnificent 9th-century Hindu temple complex and UNESCO World Heritage Site, renowned for its towering spires and the Ramayana Ballet performance held under the stars.','template/assets/images/destination/2.jpg','Sleman, Yogyakarta','Yogyakarta',4.80,20,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3953.705642143!2d110.48949807498!3d-7.752020292479!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a59755d4c0001%3A0x6d9f9c5c5c5c5c5c!2sPrambanan%20Temple!5e0!3m2!1sen!2sid!4v1700000000000!5m2!1sen!2sid\" width=\"100%\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>','https://maps.app.goo.gl/prambanan',NULL,1,1,'2026-07-09 00:15:27','2026-07-10 07:07:02'),(3,'Malioboro Street','malioboro-street','<p><strong>Malioboro Street</strong> is the beating heart of Yogyakarta and arguably the most famous street in Indonesia. Stretching approximately 2 kilometers from the Yogyakarta Kraton (Sultan\'s Palace) in the south to the Tugu Monumen in the north, this bustling thoroughfare is the city\'s primary shopping, dining, and cultural corridor.</p>\n<h4>Shopping</h4>\n<p>Malioboro is a shopper\'s paradise. The sidewalks are lined with vendors selling <strong>batik clothing</strong>, handmade leather <strong>wayang</strong> (shadow puppets), silver jewelry, traditional Javanese masks, and an endless array of souvenirs. The large <strong>Malioboro Mall</strong> and <strong>Beringharjo Market</strong> (Yogyakarta\'s oldest traditional market) offer everything from textiles to spices at negotiable prices.</p>\n<h4>Street Food</h4>\n<p>The street is legendary for its Javanese street food. Must-try items include:</p>\n<ul>\n<li><strong>Gudeg</strong> ΓÇö young jackfruit stewed in coconut milk and palm sugar, Yogyakarta\'s signature dish</li>\n<li><strong>Bakpia Pathok</strong> ΓÇö sweet rolled pastries filled with mung bean, a classic Jogja treat</li>\n<li><strong>Sate Klathak</strong> ΓÇö goat satay served on bicycle spokes</li>\n<li><strong>Angkringan</strong> ΓÇö tiny roadside stalls serving rice, side dishes, and sweet Javanese coffee (kopi joss)</li>\n<li><strong>Kue Cubit</strong> ΓÇö bite-sized sweet pancakes cooked in a special molded pan</li>\n</ul>\n<h4>Evening & Nightlife</h4>\n<p>Malioboro transforms at night. Street musicians, traditional <strong>batik painting</strong> demonstrations, and impromptu performances bring the street alive. Horse-drawn carriages (<em>andong</em>) and pedicabs (<em>becak</em>) add to the old-world charm. On weekend nights, sections of the street become pedestrian-only zones.</p>\n<h4>Visitor Tips</h4>\n<ul>\n<li>Visit in the late afternoon to evening for the best atmosphere</li>\n<li>Bargaining is expected at sidewalk stalls (start at 50% of asking price)</li>\n<li>Keep belongings secure ΓÇö it gets very crowded</li>\n<li>The Tugu Monument at the northern end is a great meeting point and photo spot</li>\n<li>The Kraton (Sultan\'s Palace) is a 10-minute walk from the southern end</li>\n</ul>\n<p>Malioboro captures the essence of Yogyakarta ΓÇö warm, vibrant, and effortlessly blending tradition with modern life.</p>','Yogyakarta\'s most iconic street ΓÇö a vibrant 2 km stretch of shops, street food, batik vendors, and street art connecting the Kraton to the Tugu Monument.','template/assets/images/destination/3.jpg','Yogyakarta','Yogyakarta',4.60,30,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3953.8!2d110.3647!3d-7.7925!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a59c9c9c9c9c9%3A0x1234567890abcdef!2sMalioboro!5e0!3m2!1sen!2sid!4v1700000000000!5m2!1sen!2sid\" width=\"100%\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>','https://maps.app.goo.gl/malioboro',NULL,1,1,'2026-07-09 00:15:27','2026-07-10 07:07:02'),(4,'Parangtritis Beach','parangtritis-beach','<p><strong>Parangtritis Beach</strong> (Pantai Parangtritis) is one of the most famous and mythologically significant beaches in Java. Located about 27 km south of Yogyakarta city center in Bantul Regency, this sweeping black-sand beach faces the full force of the Indian Ocean and carries deep spiritual significance in Javanese culture.</p>\n<h4>Mythology & Legend</h4>\n<p>Parangtritis is believed to be the gateway to the mystical <strong>Nyai Roro Kidul</strong> (Queen of the Southern Sea). According to Javanese legend, wearing green clothing on this beach invites the queen\'s wrath, and it is forbidden ΓÇö a tradition locals still respect today. The beach has long been a site for spiritual retreats and Javanese meditation rituals.</p>\n<h4>Activities</h4>\n<ul>\n<li><strong>ATV & Jeep Riding</strong> ΓÇö ride across the vast sand dunes and through the coastal forest</li>\n<li><strong>Horse Riding</strong> ΓÇö traditional horse-back rides along the beach at sunset</li>\n<li><strong>Paragliding</strong> ΓÇö tandem flights from the nearby Parang Endog cliff</li>\n<li><strong>Sand Dunes</strong> ΓÇö explore the rolling hills of volcanic sand that stretch inland</li>\n<li><strong>Ngunduh Suduk</strong> ΓÇö a local tradition of collecting sand for spiritual purposes</li>\n</ul>\n<h4>Gumuk Pasir (Sand Dunes)</h4>\n<p>One of Parangtritis\'s most unique features is the <strong>Gumuk Pasir</strong> ΓÇö a vast stretch of volcanic sand dunes extending from the beach into the pine forest. This rare landscape is one of only a few in Southeast Asia and is a popular spot for photography, sandboarding, and ATV adventures.</p>\n<h4>Visitor Tips</h4>\n<ul>\n<li>The waves are extremely powerful ΓÇö <strong>do not swim</strong>; the undertow is dangerous</li>\n<li>Visit in the late afternoon for spectacular sunsets over the Indian Ocean</li>\n<li>Wear closed shoes for walking on hot black sand</li>\n<li>Avoid wearing green clothing (respecting local custom)</li>\n<li>The beach can be windy ΓÇö bring a light jacket for evening visits</li>\n<li>Parking is available at the main entrance with warung stalls nearby</li>\n</ul>\n<p>Parangtritis offers a raw, untamed coastal experience steeped in Javanese mysticism ΓÇö a stark contrast to the city\'s bustling streets.</p>','A dramatic black-sand beach on the Indian Ocean, famous for its powerful waves, mystical Javanese mythology, and spectacular sunset views.','template/assets/images/destination/des1.jpg','Bantul, Yogyakarta','Yogyakarta',4.50,18,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3954.5!2d110.3872!3d-8.0235!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a5b5b5b5b5b5b%3A0x1234567890abcdef!2sParangtritis!5e0!3m2!1sen!2sid!4v1700000000000!5m2!1sen!2sid\" width=\"100%\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>','https://maps.app.goo.gl/parangtritis',NULL,1,1,'2026-07-09 00:15:27','2026-07-10 07:07:02'),(5,'Jomblang Cave','jomblang-cave','<p><strong>Jomblang Cave</strong> (Gua Jomblang) is one of Yogyakarta\'s most extraordinary natural wonders, located in the Gunung Kidul karst region about 40 km southeast of the city center. This vertical cave is famous worldwide for its ethereal light beam that streams through a sinkhole onto an ancient forest growing on the cave floor.</p>\n<h4>The Light of Heaven</h4>\n<p>The cave\'s most breathtaking moment occurs between <strong>10:00 AM and 12:00 PM</strong> when sunlight pours through a narrow opening above, creating a dramatic shaft of golden light that illuminates the cave\'s lush green vegetation below. This phenomenon ΓÇö known as the <em>\"Light of Heaven\"</em> ΓÇö is unlike anything else in Java and attracts photographers and travelers from around the world.</p>\n<h4>The Descent</h4>\n<p>Reaching the cave floor requires a <strong>60-meter rappel</strong> down a vertical shaft using professional caving equipment. Trained guides manage all the technical gear, making this accessible even for first-time cavers. The descent takes approximately 15-20 minutes and the experience is both thrilling and safe.</p>\n<h4>What You\'ll Find Inside</h4>\n<ul>\n<li>Ancient forest with towering ferns and tropical vegetation thriving in the cave\'s humid microclimate</li>\n<li>A connecting tunnel (approximately 300 meters long) leading to <strong>Grubug Cave</strong>, the largest vertical cave in Southeast Asia</li>\n<li>Unique cave formations and stalactites</li>\n<li>A cool underground environment (around 20┬░C)</li>\n</ul>\n<h4>Visitor Tips</h4>\n<ul>\n<li><strong>Book in advance</strong> ΓÇö daily visitor numbers are limited</li>\n<li>Arrive before 10:00 AM for the best light conditions</li>\n<li>Wear clothes that can get dirty and wet (the cave floor is muddy)</li>\n<li>Closed-toe shoes with good grip are required (rentals available)</li>\n<li>Bring a waterproof camera or phone case</li>\n<li>The cave is not suitable for those with severe claustrophobia or mobility issues</li>\n<li>Combo tickets with nearby <strong>Timang Beach</strong> or <strong>Indrayanti Beach</strong> are available</li>\n</ul>\n<p>Jomblang Cave is a bucket-list adventure for nature lovers and photographers ΓÇö a reminder that some of Yogyakarta\'s greatest treasures lie beneath the surface.</p>','A vertical cave in Gunung Kidul famous for its heavenly light beam that illuminates an ancient forest on the cave floor.','template/assets/images/destination/des2.jpg','Gunung Kidul, Yogyakarta','Yogyakarta',4.70,12,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3955.2!2d110.6!3d-7.95!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a5c5c5c5c5c5c%3A0x1234567890abcdef!2sJomblang%20Cave!5e0!3m2!1sen!2sid!4v1700000000000!5m2!1sen!2sid\" width=\"100%\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>','https://maps.app.goo.gl/jomblang',NULL,0,1,'2026-07-09 00:15:27','2026-07-10 07:07:02'),(6,'Taman Sari Water Castle','taman-sari-water-castle','<p><strong>Taman Sari Water Castle</strong> (Taman Sari) is a stunning 18th-century royal garden complex built by Sultan Hamengkubuwono I, the founder of the Yogyakarta Sultanate, in 1758. Located just 2 km south of the Kraton (Sultan\'s Palace), this tranquil retreat served as a place of rest, meditation, and recreation for the royal family.</p>\n<h4>History</h4>\n<p>Taman Sari ΓÇö meaning <em>\"Fragrant Garden\"</em> ΓÇö was originally a vast complex of over 60 buildings, pools, gardens, and canals. It was designed by a Portuguese architect and featured a blend of Javanese, European, and Chinese architectural styles. The complex was damaged by British bombardment during the Java War of 1812 and subsequent earthquakes, but its core structures remain remarkably preserved.</p>\n<h4>Key Areas</h4>\n<ul>\n<li><strong>Kolam Segaran (Swimming Pool)</strong> ΓÇö the largest pool, once reserved for the Sultan\'s wives and concubines, now open for visitors to swim in</li>\n<li><strong>Kolam Pulau Kenanga (Kenanga Island Pool)</strong> ΓÇö the iconic sunken pool with a central island, connected by underground tunnels</li>\n<li><strong>Umbul Pasiraman</strong> ΓÇö the bathing complex where the Sultan and his family relaxed</li>\n<li><strong>Sumur Gumuling (Underground Mosque)</strong> ΓÇö a mysterious underground mosque accessed through narrow tunnels, featuring a circular central chamber</li>\n<li><strong>Regol Keben</strong> ΓÇö the grand entrance gate with ornate Javanese carvings</li>\n</ul>\n<h4>Secret Tunnels</h4>\n<p>Beneath Taman Sari lies a network of <strong>underground tunnels</strong> that once connected different parts of the complex. The tunnels also served as escape routes in times of danger. Exploring these narrow passages adds an element of mystery and adventure to any visit.</p>\n<h4>Pesarean Taman Sari</h4>\n<p>The area surrounding the water castle has transformed into a charming neighborhood known as <strong>Kampung Taman Sari</strong> or <strong>\"Kampung Kauman\"</strong>, where local artisans craft silver jewelry, batik, and traditional Javanese handicrafts. The nearby <strong>Sultan\'s Mosque (Masjid Agung)</strong> is also worth visiting.</p>\n<h4>Visitor Tips</h4>\n<ul>\n<li>Entry ticket: approximately IDR 5,000 (very affordable)</li>\n<li>You can swim in Kolam Segaran ΓÇö bring a swimsuit or change clothes</li>\n<li>Visit early morning or late afternoon for the best photos and fewer crowds</li>\n<li>Explore the surrounding silver workshops for unique handmade souvenirs</li>\n<li>The complex is walkable in about 1-2 hours at a leisurely pace</li>\n<li>Combine with a visit to the Kraton (Sultan\'s Palace) ΓÇö they are very close</li>\n</ul>\n<p>Taman Sari is a peaceful oasis in the heart of Yogyakarta, offering a glimpse into the elegance and mystery of Javanese royal life.</p>','A serene 18th-century royal garden and water castle built by the first Sultan of Yogyakarta, featuring bathing pools, underground tunnels, and a floating mosque.','template/assets/images/destination/des3.jpg','Yogyakarta','Yogyakarta',4.40,15,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3953.8!2d110.3542!3d-7.8105!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a5a5a5a5a5a5a%3A0x1234567890abcdef!2sTaman%20Sari!5e0!3m2!1sen!2sid!4v1700000000000!5m2!1sen!2sid\" width=\"100%\" height=\"450\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"no-referrer-when-downgrade\"></iframe>','https://maps.app.goo.gl/tamansari',NULL,0,1,'2026-07-09 00:15:27','2026-07-10 07:07:02'),(7,'Timang Beach','timang-beach','<p><strong>Timang Beach</strong> is one of the most adrenaline-pumping destinations in Gunung Kidul, Yogyakarta. It is famous for the hand-pulled wooden cable car (gondola) that swings visitors across the crashing waves to the tiny <em>Panjang Island</em>.</p><h4>The Cable Car Experience</h4><p>The traditional gondola is operated manually by local villagers using a system of pulleys and ropes. The ride offers breathtaking ocean views and a thrilling sense of adventure above the Indian Ocean.</p><h4>Activities</h4><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Ride the manual cable car to Panjang Island</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Fresh grilled lobster and seafood on the beach</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Photography of the dramatic limestone cliffs</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Explore nearby quiet coves</li></ol><h4>Good to Know</h4><p>The ride is not for the faint-hearted. Wear comfortable clothes, bring cash for the gondola fare, and visit in the morning for calmer seas.</p>','<p>A rugged Gunung Kidul beach famous for its wooden cable car ride to Panjang Island.</p>','destinations/gallery/pantai-timang-scaled_1783691270.webp','Gunung Kidul, Yogyakarta','Yogyakarta',4.60,14,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d4684.609310561101!2d110.65990187575524!3d-8.176087981955355!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7bb36265782cf3%3A0x25efcb5e3a28afa8!2sPantai%20Timang!5e1!3m2!1sid!2sid!4v1783691199914!5m2!1sid!2sid\" width=\"100%\" height=\"100%\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"strict-origin-when-cross-origin\"></iframe>','https://maps.app.goo.gl/yiX88ic4Du5EssMa9','[\"template/assets/images/destination/des1.jpg\", \"template/assets/images/destination/des2.jpg\", \"template/assets/images/destination/des3.jpg\", \"template/assets/images/destination/des5.jpg\"]',1,1,'2026-07-10 06:44:08','2026-07-10 06:47:51'),(8,'Ratu Boko Temple','ratu-boko-temple','<p><strong>Ratu Boko Temple</strong> (Kraton Ratu Boko) is an archaeological site perched on a hill in Sleman, Yogyakarta. More a royal complex than a single temple, it features gateways, bathing pools, and pavilions with sweeping views of the surrounding plains.</p><h4>History</h4><p>The site dates back to the 8thΓÇô9th centuries and shows a blend of Hindu and Buddhist influences. Its exact original function remains debated among historians.</p><h4>Sunset Viewpoint</h4><p>Ratu Boko is renowned as one of the best sunset spots near Yogyakarta, with Prambanan and Mount Merapi visible in the distance as the sky turns golden.</p><h4>Facilities</h4><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Well-maintained pathways and gardens</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Open-air amphitheater for cultural performances</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Caf├⌐ and rest areas</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Guided tours available</li></ol>','<p>An archaeological hilltop site in Sleman known for royal ruins and spectacular sunsets.</p>','destinations/gallery/5e146f3988fbb_1783691179.webp','Sleman, Yogyakarta','Yogyakarta',4.50,16,'<iframe src=\"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d4689.255672493429!2d110.48614219999999!3d-7.770568300000001!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x2e7a5a92d354fe45%3A0x153f44f14476f95b!2sKeraton%20Ratu%20Boko!5e1!3m2!1sid!2sid!4v1783691155980!5m2!1sid!2sid\" width=\"100%\" height=\"100%\" style=\"border:0;\" allowfullscreen=\"\" loading=\"lazy\" referrerpolicy=\"strict-origin-when-cross-origin\"></iframe>','https://maps.app.goo.gl/crAGByeszN84XFHP9','[\"template/assets/images/destination/des1.jpg\", \"template/assets/images/destination/des2.jpg\", \"template/assets/images/destination/des4.jpg\", \"template/assets/images/destination/1.jpg\"]',1,1,'2026-07-10 06:44:08','2026-07-10 06:46:19'),(9,'Air Terjun Tumpak Sewu','tumpak-sewu-waterfall','<p><strong>Air Terjun Tumpak Sewu</strong> is a spectacular 120-meter waterfall located in Lumajang, East Java, about 3-4 hours from Yogyakarta. Often called the <em>Niagara of Java</em>, it is widely regarded as one of the most beautiful waterfalls in Indonesia.</p><h4>The Waterfall</h4><p>Tumpak Sewu means <em>thousand waterfalls</em> in Javanese, named for the way the water fans out across the cliff face in dozens of thin cascades before converging into a single powerful plunge.</p><h4>What to See</h4><ul><li><strong>Main Waterfall</strong> - the 120-meter central cascade</li><li><strong>Viewpoint</strong> - cliffside panoramic views</li><li><strong>Goa Tetes</strong> - stalactite cave</li><li><strong>Blue Canyon Pool</strong> - turquoise swimming pool</li></ul><h4>Visitor Tips</h4><ul><li>Best during rainy season (Nov-Apr)</li><li>Wear sturdy shoes</li><li>Start early morning</li><li>Hire a local guide</li></ul>','A majestic 120-meter waterfall often called the most beautiful in East Java.','template/assets/images/destination/des1.jpg','Lumajang, East Java','Lumajang',4.80,8,NULL,'https://www.google.com/maps/search/?api=1&query=Tumpak+Sewu','[]',1,1,'2026-07-10 09:58:31','2026-07-10 09:59:23'),(10,'Keraton Yogyakarta','keraton-yogyakarta','<p><strong>Keraton Yogyakarta</strong> (Kraton Ngayogyakarta Hadiningrat) is the official palace of the reigning Sultan of Yogyakarta. Built in 1755 by Sultan Hamengkubuwono I, it remains the spiritual and cultural heart of the city.</p><h4>Architecture</h4><p>A masterpiece of Javanese architecture with interconnected courtyards, pavilions (pendopo), and gardens. The <strong>Pendopo Ageng</strong> is a magnificent open-air hall with carved wooden pillars and a traditional joglo roof.</p><h4>Cultural Experiences</h4><ul><li><strong>Guided Tours</strong> - daily English tours explaining history and symbolism</li><li><strong>Gamelan Music</strong> - traditional performances held daily</li><li><strong>Wayang Kulit</strong> - shadow puppet performances</li><li><strong>Batik Making</strong> - traditional wax-resist dyeing demonstrations</li><li><strong>Taman Sari</strong> - the Water Castle is included in the visit</li></ul><h4>Historical Significance</h4><p>The keraton has survived colonial Dutch occupation and the Java War of 1812. It remains the residence of Sultan Hamengkubuwono X, who also serves as Governor of the Special Region of Yogyakarta.</p><h4>Visitor Tips</h4><ul><li>Open daily 8:30 AM to 2:00 PM (closed Friday mornings)</li><li>Entry: approximately IDR 15,000</li><li>Wear modest clothing</li><li>Guided tours included</li><li>Combine with Taman Sari visit (5-minute walk)</li></ul>','The official palace of the Sultan of Yogyakarta, a living museum of Javanese royal culture.','template/assets/images/destination/des2.jpg','Yogyakarta','Yogyakarta',4.60,22,NULL,'https://www.google.com/maps/search/?api=1&query=Keraton+Yogyakarta','[\"template/assets/images/destination/des1.jpg\", \"template/assets/images/destination/des3.jpg\", \"template/assets/images/destination/des4.jpg\", \"template/assets/images/destination/des5.jpg\"]',1,1,'2026-07-10 10:00:13','2026-07-10 10:00:13'),(11,'Purawisata Amphitheater','purawisata-amphitheater','<p><strong>Purawisata Amphitheater</strong> is a prominent cultural venue near Malioboro Street, serving as a premier stage for traditional Javanese performing arts.</p><h4>Performances</h4><ul><li><strong>Wayang Kulit</strong> - shadow puppet shows with live gamelan orchestra</li><li><strong>Jaeger Dance</strong> - dynamic warrior dance in traditional costume</li><li><strong>Bekso Dance</strong> - lively and humorous Javanese dance</li><li><strong>Gamelan Orchestra</strong> - traditional bronze percussion ensembles</li></ul><h4>The Venue</h4><p>Open-air amphitheater with tiered seating. The stage resembles a traditional Javanese pendopo. Includes a food court serving local cuisine.</p><h4>Dining</h4><p>Food court serving gudeg, bakso, nasi goreng, and Javanese specialties while watching evening performances.</p><h4>Visitor Tips</h4><ul><li>Evening shows 7:00 PM to 9:00 PM</li><li>Entry: IDR 10,000 to 25,000</li><li>Short walk from Malioboro Street</li><li>Family-friendly venue</li></ul>','A cultural amphitheater hosting traditional Javanese dance performances and wayang kulit shows.','template/assets/images/destination/des3.jpg','Yogyakarta','Yogyakarta',4.40,12,NULL,'https://www.google.com/maps/search/?api=1&query=Purawisata+Amphitheater+Yogyakarta','[\"template/assets/images/destination/des1.jpg\", \"template/assets/images/destination/des2.jpg\", \"template/assets/images/destination/des4.jpg\", \"template/assets/images/destination/des5.jpg\"]',0,1,'2026-07-10 10:00:13','2026-07-10 10:00:13'); /*!40000 ALTER TABLE `destinations` ENABLE KEYS */; UNLOCK TABLES;  -- -- Table structure for table `failed_jobs` --  DROP TABLE IF EXISTS `failed_jobs`; /*!40101 SET @saved_cs_client     = @@character_set_client */; /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `failed_jobs` (   `id` bigint unsigned NOT NULL AUTO_INCREMENT,   `uuid` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `connection` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `queue` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,   `payload` longtext COLLATE utf8mb4_unicode_ci NOT NULL,   `exception` longtext COLLATE utf8mb4_unicode_ci NOT NULL,   `failed_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,   PRIMARY KEY (`id`),   UNIQUE KEY `failed_jobs_uuid_unique` (`uuid`),   KEY `failed_jobs_connection_queue_failed_at_index` (`connection`,`queue`,`failed_at`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci; /*!40101 SET character_set_client = @saved_cs_client */;  -- -- Dumping data for table `failed_jobs` --  LOCK TABLES `failed_jobs` WRITE; /*!40000 ALTER TABLE `failed_jobs` DISABLE KEYS */; /*!40000 ALTER TABLE `failed_jobs` ENABLE KEYS */; UNLOCK TABLES;  -- -- Table structure for table `faqs` --  DROP TABLE IF EXISTS `faqs`; /*!40101 SET @saved_cs_client     = @@character_set_client */; /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `faqs` (   `id` bigint unsigned NOT NULL 